import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { PROJECTS } from '../constants';
import { MapPin, X } from 'lucide-react';

// Fix for default Leaflet marker icons in React
import icon from 'leaflet/dist/images/marker-icon.png';
import iconShadow from 'leaflet/dist/images/marker-shadow.png';

let DefaultIcon = L.icon({
    iconUrl: icon,
    shadowUrl: iconShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41],
});

L.Marker.prototype.options.icon = DefaultIcon;

// Custom Icon definition
const customIcon = new L.Icon({
  iconUrl: 'https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-2x-orange.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/0.7.7/images/marker-shadow.png',
  iconSize: [25, 41],
  iconAnchor: [12, 41],
  popupAnchor: [1, -34],
  shadowSize: [41, 41]
});

// Component to handle map invalidation on mount
const MapUpdater = () => {
  const map = useMap();
  useEffect(() => {
    map.invalidateSize();
  }, [map]);
  return null;
};

const ProjectsMap = () => {
  const [showOverlayCard, setShowOverlayCard] = useState(true);

  // Center of Argentina (approx)
  const centerPosition: [number, number] = [-38.4161, -63.6167];
  const zoomLevel = 4;

  return (
    <section id="obras" className="relative bg-slate-900 border-t border-slate-800">
      <div className="absolute top-0 left-0 w-full z-10 pointer-events-none p-8 md:p-12 bg-gradient-to-b from-slate-900/90 to-transparent h-48">
        <div className="max-w-7xl mx-auto px-4">
          <h2 className="text-3xl font-bold text-white text-center md:text-left drop-shadow-md">
            Obras Realizadas
          </h2>
          <p className="text-orange-400 font-medium text-center md:text-left drop-shadow-sm">
            Proyectos ejecutados por Galtech en todo el país
          </p>
        </div>
      </div>

      <div className="h-[600px] md:h-[700px] w-full relative z-0">
        <MapContainer 
          center={centerPosition} 
          zoom={zoomLevel} 
          scrollWheelZoom={false} 
          style={{ height: '100%', width: '100%' }}
          className="z-0"
        >
          <MapUpdater />
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
            url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
          />

          {PROJECTS.map((project) => (
            <Marker 
              key={project.id} 
              position={[project.lat, project.lng]} 
              icon={customIcon}
            >
              <Popup>
                <div className="w-full">
                  <div className="h-32 w-full mb-3 overflow-hidden rounded-sm relative">
                    <img 
                      src={project.imageUrl} 
                      alt={project.title} 
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute bottom-0 left-0 bg-orange-600 text-white text-xs font-bold px-2 py-1">
                      {project.year}
                    </div>
                  </div>
                  <h3 className="font-bold text-slate-900 text-sm mb-1">{project.title}</h3>
                  <div className="text-xs text-slate-600 flex items-center mb-1">
                    <MapPin size={12} className="mr-1" /> {project.location}
                  </div>
                  <div className="border-t border-slate-100 mt-2 pt-2 grid grid-cols-2 gap-2 text-xs">
                    <div>
                      <span className="block text-slate-400">Superficie</span>
                      <span className="font-semibold text-slate-800">{project.area}</span>
                    </div>
                    <div>
                      <span className="block text-slate-400">Tipo</span>
                      <span className="font-semibold text-slate-800">{project.type}</span>
                    </div>
                  </div>
                </div>
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {/* Floating Info Card (Desktop Only) */}
      {showOverlayCard && (
        <div className="hidden lg:block absolute bottom-12 right-12 z-[1000] w-80 bg-white shadow-2xl rounded-sm border-l-4 border-orange-500 animate-fade-in-up">
          <div className="p-6 relative">
            <button 
              onClick={() => setShowOverlayCard(false)}
              className="absolute top-2 right-2 text-slate-400 hover:text-slate-600"
            >
              <X size={16} />
            </button>
            <h3 className="font-bold text-lg text-slate-900 mb-2">Presencia Nacional</h3>
            <p className="text-sm text-slate-600 leading-relaxed">
              Nuestra logística nos permite ejecutar obras de gran envergadura en cualquier punto del territorio nacional, garantizando los mismos estándares de calidad y cumplimiento, desde el norte hasta la Patagonia.
            </p>
          </div>
        </div>
      )}
    </section>
  );
};

