                    <MapPin size={12} className="mr-1" /> {project.location}
                  </div>
                  <div className="border-t border-slate-100 mt-2 pt-2 grid grid-cols-2 gap-2 text-xs">
                    <div>
                      <span className="block text-slate-400">Superficie</span>
                      <span className="font-semibold text-slate-800">{project.area}</span>
                    </div>
                    <div>
                      <span className="block text-slate-400">Tipo</span>
                      <span className="font-semibold text-slate-800">{project.type}</span>
                    </div>
                  </div>
                </div>
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {/* Floating Info Card (Desktop Only) */}
      {showOverlayCard && (
        <div className="hidden lg:block absolute bottom-12 right-12 z-[1000] w-80 bg-white shadow-2xl rounded-sm border-l-4 border-orange-500 animate-fade-in-up">
          <div className="p-6 relative">
            <button 
              onClick={() => setShowOverlayCard(false)}
              className="absolute top-2 right-2 text-slate-400 hover:text-slate-600"
            >
              <X size={16} />
            </button>
            <h3 className="font-bold text-lg text-slate-900 mb-2">Presencia Nacional</h3>
            <p className="text-sm text-slate-600 leading-relaxed">
              Nuestra logística nos permite ejecutar obras de gran envergadura en cualquier punto del territorio nacional, garantizando los mismos estándares de calidad y cumplimiento, desde el norte hasta la Patagonia.
            </p>
          </div>
        </div>
      )}
    </section>
  );
};

export default ProjectsMap;
